pub fn set_len(&mut self, new_len: usize) {
>	self.len = new_len;
}

pub fn from_raw(ptr: *mut u8, len: usize) -> Vec<u8> {
>	Vec::from_raw_parts(ptr, len, len)
}

pub fn checked_add(a: u32, b: u32) -> Option<u32> {
>	a.checked_add(b)
}

pub fn double(x: i64) -> i64 {
>	x.saturating_mul(2)
}
